protected static void writeHeaders(Header[] hdrs,DataOutput out,short... excluded_headers) throws IOException {
  int size=Headers.size(hdrs,excluded_headers);
  out.writeShort(size);
  if (size > 0) {
    for (    Header hdr : hdrs) {
      if (hdr == null)       break;
      short id=hdr.getProtId();
