 else         rsp.setValue((T)response_value);
        num_valid++;
      }
    }
    if (responsesComplete() || (rsp_filter != null && !rsp_filter.needMoreResponses())) {
      complete(this.rsps);
      corrDone();
    }
  }
  finally {
    lock.unlock();
  }
}

