  final int num_total=rsps.size();
switch (options.mode()) {
case GET_FIRST:
    return num_valid >= 1 || num_received >= num_total;
case GET_ALL:
  return num_valid >= num_total || num_received >= num_total;
case GET_NONE:
return true;
}
