  try {
    for (    Map.Entry<Address,Rsp<T>> entry : rsps.entrySet()) {
      Address member=entry.getKey();
      if (!(member instanceof SiteAddress))       continue;
      SiteAddress addr=(SiteAddress)member;
      if (addr.getSite().equals(site)) {
