public void transportClosed(){
  boolean changed=false;
  lock.lock();
  try {
    for (    Map.Entry<Address,Rsp<T>> entry : rsps.entrySet()) {
      Rsp<T> rsp=entry.getValue();
      if (rsp != null && !(rsp.wasReceived() || rsp.wasSuspected() || rsp.wasUnreachable())) {
