  if (keys == null || keys.isEmpty())   return;
  if (force)   map.keySet().retainAll(keys);
 else {
    map.entrySet().stream().filter(entry -> !keys.contains(entry.getKey())).forEach(entry -> {
      Entry<V> val=entry.getValue();
      if (val != null)       val.setRemovable(true);
    }
);
