protected Object handleUpEvent(Event evt) throws Exception {
switch (evt.getType()) {
case Event.GET_APPLSTATE:
    byte[] tmp_state=null;
  if (receiver != null) {
    ByteArrayOutputStream output=new ByteArrayOutputStream(1024);
    if (getState(output))     tmp_state=output.toByteArray();
  }
return new StateTransferInfo(null,0L,tmp_state);
case Event.GET_STATE_OK:
if (receiver != null) {
StateTransferResult result=evt.getArg();
if (result.hasBuffer()) {
  ByteArrayInputStream input=new ByteArrayInputStream(result.getBuffer());
  setState(input);
}
}
break;
case Event.STATE_TRANSFER_OUTPUTSTREAM:
OutputStream os=evt.getArg();
getState(os);
break;
case Event.STATE_TRANSFER_INPUTSTREAM:
InputStream is=evt.getArg();
setState(is);
break;
case Event.VIEW_CHANGE:
View v=evt.getArg();
List<Address> new_mbrs=v.getMembers();
setMembers(new_mbrs);
if (receiver != null) receiver.viewAccepted(v);
break;
case Event.BLOCK:
if (receiver != null) receiver.block();
break;
case Event.UNBLOCK:
if (receiver != null) receiver.unblock();
break;
}
return null;
}

