public Object handle(Message req) throws Exception {
  if (server_obj == null) {
    log.error(Util.getMessage("NoMethodHandlerIsRegisteredDiscardingRequest"));
    return null;
  }
  if (req == null || req.getLength() == 0) {
    log.error(Util.getMessage("MessageOrMessageBufferIsNull"));
    return null;
  }
  MethodCall method_call=req.getObject();
  if (log.isTraceEnabled())   log.trace("[sender=%s], method_call: %s",req.getSrc(),method_call);
  if (method_call.useIds()) {
    if (method_invoker != null)     return method_invoker.invoke(server_obj,method_call.getMethodId(),method_call.getArgs());
    if (method_lookup == null)     throw new Exception(String.format("MethodCall uses ID=%d, but method_lookup has not been set",method_call.getMethodId()));
    Method m=method_lookup.findMethod(method_call.getMethodId());
    if (m == null)     throw new Exception("no method found for " + method_call.getMethodId());
    method_call.setMethod(m);
  }
  return method_call.invoke(server_obj);
}

