synchronized (state) {
    DataOutputStream dos=new DataOutputStream(outstream);
    dos.writeInt(state.size());
    Point point;
    Color col;
    for (    Map.Entry<Point,Color> entry : state.entrySet()) {
      point=entry.getKey();
      col=entry.getValue();
      dos.writeInt(point.x);
      dos.writeInt(point.y);
      dos.writeInt(col.getRGB());
    }
    dos.flush();
  }
}

