protected void joinInternal(Address mbr,boolean joinWithStateTransfer,boolean useFlushIfPresent){
  int join_attempts=0;
  join_promise.reset();
  Responses responses=null;
  try {
    while (!gms.isLeaving()) {
      if (installViewIfValidJoinRsp(join_promise,false))       return;
      long start=System.currentTimeMillis();
      if (responses == null)       responses=(Responses)gms.getDownProtocol().down(new Event(Event.FIND_INITIAL_MBRS,gms.getJoinTimeout()));
 else {
        Responses tmp=(Responses)gms.getDownProtocol().down(new Event(Event.FIND_INITIAL_MBRS,gms.getJoinTimeout()));
        if (tmp != null) {
          responses.add(tmp,gms.getAddress());
          tmp.done();
        }
      }
      if (installViewIfValidJoinRsp(join_promise,false))       return;
      responses.waitFor(gms.join_timeout);
      long diff=System.currentTimeMillis() - start;
      boolean empty;
      if ((empty=responses.isEmpty()) || responses.isCoord(gms.getAddress())) {
        log.info("%s: %s: creating cluster as coordinator",gms.getAddress(),empty ? String.format("no members discovered after %d ms",diff) : "I'm the first member");
        becomeSingletonMember(mbr);
        return;
      }
      log.trace("%s: discovery took %d ms, members: %s",gms.getAddress(),diff,responses);
      List<Address> coords=getCoords(responses);
      if (coords == null) {
        if (firstOfAllClients(mbr,responses))         return;
      }
 else {
        if (coords.size() > 1) {
          log.debug("%s: found multiple coords: %s",gms.getAddress(),coords);
          Collections.shuffle(coords);
        }
        for (        Address coord : coords) {
          log.debug("%s: sending JOIN(%s) to %s",gms.getAddress(),mbr,coord);
          sendJoinMessage(coord,mbr,joinWithStateTransfer,useFlushIfPresent);
          if (installViewIfValidJoinRsp(join_promise,true))           return;
          log.warn("%s: JOIN(%s) sent to %s timed out (after %d ms), on try %d",gms.getAddress(),mbr,coord,gms.join_timeout,join_attempts);
        }
      }
      if (gms.max_join_attempts > 0 && ++join_attempts >= gms.max_join_attempts) {
        log.warn("%s: too many JOIN attempts (%d): becoming singleton",gms.getAddress(),join_attempts);
        becomeSingletonMember(mbr);
        return;
      }
    }
  }
  finally {
    if (responses != null)     responses.done();
  }
}

