  if (!leaving.compareAndSet(false,true)) {
    coord=gms.getCoord();
    if (coord == null) {
      log.trace("%s: last member in the group (coord); leaving now",me);
      leave_promise.setResult(me);
    }
 else {
      log.trace("%s: re-sending LEAVE request to %s",me,coord);
      sendLeaveRequest(coord,me);
