  final List<Address> current_mbrs=view.getMembers();
  if (current_mbrs == null || current_mbrs.size() == 1 && current_mbrs.get(0).equals(gms.getAddress()))   return new MutableDigest(view.getMembersRaw()).set((Digest)gms.getDownProtocol().down(new Event(Event.GET_DIGEST,gms.getAddress())));
  Message get_digest_req=new EmptyMessage().setFlag(OOB).setFlag(DONT_LOOPBACK).putHeader(gms.getId(),new GMS.GmsHeader(GMS.GmsHeader.GET_DIGEST_REQ).mergeId(merge_id));
  long max_wait_time=gms.merge_timeout / 2;
  digest_collector.reset(current_mbrs);
  long start=System.currentTimeMillis();
  gms.getDownProtocol().down(get_digest_req);
  Digest digest=(Digest)gms.getDownProtocol().down(new Event(Event.GET_DIGEST,gms.getAddress()));
  digest_collector.add(gms.getAddress(),digest);
  digest_collector.waitForAllResponses(max_wait_time);
  if (log.isTraceEnabled()) {
    if (digest_collector.hasAllResponses())     log.trace("%s: fetched all digests for %s in %d ms",gms.getAddress(),current_mbrs,System.currentTimeMillis() - start);
 else     log.trace("%s: fetched incomplete digests (after timeout of %d) ms for %s",gms.getAddress(),max_wait_time,current_mbrs);
  }
  List<Address> valid_rsps=new ArrayList<>(current_mbrs);
  valid_rsps.removeAll(digest_collector.getMissing());
  Address[] tmp=new Address[valid_rsps.size()];
  valid_rsps.toArray(tmp);
  MutableDigest retval=new MutableDigest(tmp);
  Map<Address,Digest> responses=new HashMap<>(digest_collector.getResults());
  responses.values().forEach(retval::set);
  return retval;
}

