  log.debug("%s: merge task %s started with %d participants",gms.getAddress(),merge_id,coords.keySet().size());
  success=getMergeDataFromSubgroupCoordinators(coords,new_merge_id,gms.merge_timeout);
  List<Address> missing=null;
  if (!success) {
    missing=merge_rsps.getMissing();
    log.debug("%s: merge leader %s did not get responses from all %d partition coordinators; " + "missing responses from %d members, removing them from the merge",gms.getAddress(),gms.getAddress(),coords.keySet().size(),missing.size());
    merge_rsps.remove(missing);
  }
  if (missing != null && !missing.isEmpty()) {
    coords.keySet().removeAll(missing);
    coordsCopy.removeAll(missing);
