public void viewAccepted(View new_view){
  this.view=new_view;
  log.trace("[Relayer " + channel.getAddress() + "] view: "+ new_view);
  Map<String,List<Address>> tmp=extract(new_view);
  Set<String> down=new HashSet<>(routes.keySet());
  Set<String> up=new HashSet<>();
  down.removeAll(tmp.keySet());
  routes.keySet().retainAll(tmp.keySet());
  for (  Map.Entry<String,List<Address>> entry : tmp.entrySet()) {
    String key=entry.getKey();
    List<Address> val=entry.getValue();
    List<Route> newRoutes;
    if (routes.containsKey(key))     newRoutes=new ArrayList<>(routes.get(key));
 else {
      newRoutes=new ArrayList<>();
      if (up != null)       up.add(key);
    }
    newRoutes.removeIf(route -> !val.contains(route.siteMaster()));
    val.stream().filter(addr -> !contains(newRoutes,addr)).forEach(addr -> newRoutes.add(new Route(addr,channel,relay,log).stats(stats)));
    if (newRoutes.isEmpty()) {
      routes.remove(key);
      down.add(key);
      up.remove(key);
    }
 else     routes.put(key,Collections.unmodifiableList(newRoutes));
  }
  if (!down.isEmpty())   relay.sitesChange(true,down.toArray(new String[0]));
  if (!up.isEmpty())   relay.sitesChange(false,up.toArray(new String[0]));
}

