public void handleView(View view){
  members=view.getMembers();
  int max_num_site_masters=max_site_masters;
  if (site_masters_ratio > 0)   max_num_site_masters=(int)Math.max(max_site_masters,site_masters_ratio * view.size());
  List<Address> old_site_masters=site_masters;
  List<Address> new_site_masters=determineSiteMasters(view,max_num_site_masters);
  boolean become_site_master=new_site_masters.contains(local_addr) && (old_site_masters == null || !old_site_masters.contains(local_addr));
  boolean cease_site_master=old_site_masters != null && old_site_masters.contains(local_addr) && !new_site_masters.contains(local_addr);
  site_masters=new_site_masters;
  if (!site_masters.isEmpty() && site_masters.get(0).equals(local_addr))   broadcast_route_notifications=true;
  if (become_site_master) {
    is_site_master=true;
    final String bridge_name="_" + NameCache.get(local_addr);
    if (relayer != null)     relayer.stop();
    relayer=new Relayer(this,log);
    final Relayer tmp=relayer;
    if (async_relay_creation)     timer.execute(() -> startRelayer(tmp,bridge_name));
 else     startRelayer(relayer,bridge_name);
    notifySiteMasterListener(true);
  }
 else {
    if (cease_site_master) {
      is_site_master=false;
      notifySiteMasterListener(false);
      log.trace(local_addr + ": ceased to be site master; closing bridges");
      if (relayer != null)       relayer.stop();
    }
  }
  if (suppress_log_no_route != null)   suppress_log_no_route.removeExpired(suppress_time_no_route_errors);
}

