newCode.7544:
protected Bundler createBundler(String bundler){
  if (bundler == null)   throw new IllegalArgumentException("bundler type has to be non-null");
  if (bundler.equals("stq"))   return new SimplifiedTransferQueueBundler(BUFSIZE);
  if (bundler.equals("tq"))   return new TransferQueueBundler(BUFSIZE);
  if (bundler.startsWith("sender-sends") || bundler.equals("ss"))   return new SenderSendsBundler();
  if (bundler.endsWith("ring-buffer") || bundler.equals("rb"))   return new RingBufferBundler(BUFSIZE);
  if (bundler.equals("ring-buffer-lockless") || bundler.equals("rbl"))   return new RingBufferBundlerLockless(BUFSIZE);
  if (bundler.equals("ring-buffer-lockless2") || bundler.equals("rbl2"))   return new RingBufferBundlerLockless2(BUFSIZE);
  if (bundler.startsWith("no-bundler") || bundler.equals("nb"))   return new NoBundler();
  try {
    Class<Bundler> clazz=(Class<Bundler>)Util.loadClass(bundler,getClass());
    return clazz.getDeclaredConstructor().newInstance();
  }
 catch (  Throwable t) {
    throw new IllegalArgumentException(String.format("failed creating instance of bundler %s: %s",bundler,t));
  }
}

