protected void loop(){
  boolean looping=true;
  while (looping) {
    int c=Util.keyPress(String.format("[1] send [2] num_msgs (%d) [3] senders (%d) [4] msg size (%d bytes)\n" + "[b] change bundler (%s) [d] details (%b) [x] exit\nbundler: %s\n",num_msgs,num_senders,msg_size,bundler.getClass().getSimpleName(),details,bundler.toString()));
    try {
switch (c) {
case '1':
        sendMessages();
      break;
case '2':
    num_msgs=Util.readIntFromStdin("num_msgs: ");
  break;
case '3':
num_senders=Util.readIntFromStdin("num_senders: ");
break;
case '4':
msg_size=Util.readIntFromStdin("msg_size: ");
break;
case 'b':
String type=null;
try {
type=Util.readStringFromStdin("new bundler type: ");
Bundler old=this.bundler;
this.bundler=createBundler(type);
this.bundler.init(transport);
this.bundler.start();
if (old != null) old.stop();
}
 catch (Throwable t) {
System.err.printf("failed changing bundler to %s: %s\n",type,t);
}
break;
case 'd':
details=!details;
break;
case 'x':
case -1:
looping=false;
break;
}
}
 catch (Throwable t) {
t.printStackTrace();
}
}
if (this.bundler != null) this.bundler.stop();
}

