protected JChannel[] createChannels(String cluster_name,String[] members) throws Exception {
  JChannel[] retval=new JChannel[members.length];
  JChannel ch=null;
  for (int i=0; i < retval.length; i++) {
    JChannel tmp;
    if (ch == null) {
      ch=createChannel();
      tmp=ch;
    }
 else {
      tmp=createChannel();
