protected static void discard(boolean flag,JChannel... channels) throws Exception {
  for (  JChannel ch : channels) {
    ProtocolStack stack=ch.getProtocolStack();
    DISCARD discard=stack.findProtocol(DISCARD.class);
    if (discard == null)     stack.insertProtocol(discard=new DISCARD(),ProtocolStack.Position.ABOVE,stack.getTransport().getClass());
    discard.discardAll(flag);
  }
}

