  if (latch == null)   return;
  System.out.println("Blocking on incoming message [PREJOIN] Timestamp: " + System.nanoTime());
  try {
    latch.countDown();
    latch.await(1,TimeUnit.MINUTES);
  }
 catch (  InterruptedException e) {
