private void send(final Address dest,final int num_msgs,final int num_threads,final double oob_prob) throws Exception {
  if (num_threads <= 0)   throw new IllegalArgumentException("number of threads <= 0");
  if (num_msgs % num_threads != 0)   throw new IllegalArgumentException("number of messages ( " + num_msgs + ") needs to be divisible by "+ "the number o threads ("+ num_threads+ ")");
  if (num_threads > 1) {
    final int msgs_per_thread=num_msgs / num_threads;
    Thread[] threads=new Thread[num_threads];
    final AtomicInteger counter=new AtomicInteger(0);
    for (int i=0; i < threads.length; i++) {
      threads[i]=new Thread(() -> {
        for (int j=0; j < msgs_per_thread; j++) {
          JChannel sender=Util.tossWeightedCoin(0.5) ? a : b;
          boolean oob=Util.tossWeightedCoin(oob_prob);
          int num=counter.incrementAndGet();
          Message msg=new BytesMessage(dest,num);
          if (oob)           msg.setFlag(Message.Flag.OOB);
          try {
            sender.send(msg);
          }
 catch (          Exception e) {
            e.printStackTrace();
          }
        }
      }
);
      threads[i].start();
    }
    for (int i=0; i < threads.length; i++) {
      threads[i].join(20000);
    }
    return;
  }
  for (int i=0; i < num_msgs; i++) {
    JChannel sender=Util.tossWeightedCoin(0.5) ? a : b;
    boolean oob=Util.tossWeightedCoin(oob_prob);
    Message msg=new BytesMessage(dest,i);
    if (oob)     msg.setFlag(Message.Flag.OOB);
    sender.send(msg);
  }
}
