protected ByteArray writeMessage(final Message msg) throws Exception {
  dos.position(0);
  byte flags=0;
  dos.writeShort(Version.version);
  if (msg.getDest() == null)   flags+=(byte)2;
  dos.writeByte(flags);
  msg.writeTo(dos);
  return new ByteArray(dos.buffer(),0,dos.position());
}

