protected static void waitersOnQueue(SizeBoundedQueue<Integer> queue,int initial_adds,int num_adders,int element_size,int max_drain_size,int expected_drained) throws InterruptedException {
  int total_adds=initial_adds + num_adders;
  for (int i=1; i <= initial_adds; i++)   queue.add(i,element_size);
  assert queue.getElements() == initial_adds && queue.size() == initial_adds * element_size;
  if (num_adders > 0) {
    Thread[] adders=new Thread[num_adders];
    for (int i=0; i < adders.length; i++) {
      final int j=i;
      adders[i]=new Thread(() -> {
        try {
          queue.add(j + initial_adds + 1,element_size);
        }
 catch (        InterruptedException e) {
        }
      }
);
      adders[i].start();
    }
    for (int i=0; i < 10; i++) {
      boolean ok=true;
      for (      Thread t : adders) {
        Thread.State state=t.getState();
switch (state) {
case NEW:
case RUNNABLE:
case TERMINATED:
          ok=false;
        break;
    }
  }
  if (ok)   break;
}
}
assert queue.getWaiters() == num_adders;
List<Integer> list=new ArrayList<>(total_adds);
int drained=queue.drainTo(list,max_drain_size);
assert drained == expected_drained * element_size && list.size() == expected_drained;
for (int i=1; i <= expected_drained; i++) assert list.contains(i);
}

