public void testFailoverWithMultipleThreadsSendingMessages() throws Exception {
  adjustConfiguration(a,b,c);
  final int num_senders=5;
  MyReceiver rb=new MyReceiver("B"), rc=new MyReceiver("C");
  b.setReceiver(rb);
  c.setReceiver(rc);
