protected void eventLoop(){
  final String INPUT="[1] Start test [2] View [4] Threads (%d) [6] Time (%,ds) [7] Msg size (%s)\n" + "[8] Number of senders (%s) [o] Toggle OOB (%s) [l] Toggle measure local messages (%s)\n" + "[s] Display message sources (%s)\n"+ "[x] Exit this [X] Exit all";
  while (looping) {
