send(null,display_msg_src_change,MPerfHeader.CONFIG_CHANGE,Message.Flag.RSVP);
break;
case 'x':
case -1:
looping=false;
break;
case 'X':
send(null,null,MPerfHeader.EXIT,Message.Flag.OOB);
break;
}
}
 catch (Throwable t) {
