      senders[i]=thread_factory.newThread(sender,"sender-" + i);
      senders[i].start();
    }
  }
  System.out.printf("-- running test for %d seconds with %d sender threads\n",time,isSender ? num_threads : 0);
  long interval=(long)((time * 1000.0) / 10.0);
  long start=System.currentTimeMillis();
  latch.countDown();
  for (int i=1; i <= 10; i++) {
    Util.sleep(interval);
    System.out.printf("%d: %s\n",i,received_msgs_map.printAverage(start,msg_size,display_msg_src));
  }
  running.set(false);
  if (isSender) {
    running.set(false);
    for (    Thread s : senders) {
      try {
        s.join();
      }
 catch (      InterruptedException e) {
        e.printStackTrace();
      }
    }
  }
  Map<Address,Long> counts=received_msgs_map.snapshot();
  Result result=new Result(System.currentTimeMillis() - start,received_msgs_map.totalCount(),counts.keySet().toArray(new Address[0]),Arrays.stream(counts.values().toArray(new Long[0])).filter(Objects::nonNull).mapToLong(Long::longValue).toArray());
  received_msgs_map.reset();
  return result;
}

