  for (int i=0; i < args.length; i++) {
    if (args[i].equals("-group")) {
      group=args[++i];
      continue;
    }
    if (args[i].equals("-details")) {
      details=true;
      continue;
    }
    System.out.println("CountTests [-group groupname] [-details]");
    return;
  }
  for (  Class<?> clazz : list) {
    Test annotation=clazz.getAnnotation(Test.class);
    if (!annotation.enabled()) {
      disabled++;
      continue;
    }
    String name=clazz.getSimpleName();
    if (details && group != null && hasGroup(annotation,group))     System.out.println(Util.bold("\n" + name + ":"));
    Method[] methods=clazz.getDeclaredMethods();
    int cnt=0;
    for (    Method method : methods) {
      int mods=method.getModifiers();
      if (!Modifier.isPublic(mods))       continue;
      if (hasAnnotations(method,BeforeSuite.class,BeforeTest.class,BeforeClass.class,BeforeMethod.class,BeforeGroups.class,AfterSuite.class,AfterClass.class,AfterTest.class,AfterMethod.class,AfterGroups.class))       continue;
      Test method_annotation=method.getAnnotation(Test.class);
      if (method_annotation != null) {
        if (method_annotation.enabled() == false) {
          disabled++;
