      total++;
      cnt++;
    }
    if (details && group != null && hasGroup(annotation,group))     System.out.println("    (" + cnt + ")");
    String[] groups=annotation.groups();
    if (groups != null) {
      for (      String grp : groups) {
        if (group != null && !grp.equals(group))         continue;
        Integer count=group_count.get(grp);
        if (count == null)         group_count.put(grp,cnt);
 else         group_count.put(grp,count + cnt);
      }
