protected static void getDescriptions(Class<?> clazz,final Map<String,String> m,String prefix,boolean print_class) throws IOException, ClassNotFoundException {
  Field[] fields=clazz.getDeclaredFields();
  for (  Field field : fields) {
    if (field.isAnnotationPresent(Property.class)) {
      String property=field.getName();
      Property annotation=field.getAnnotation(Property.class);
      String name=annotation.name();
      if (name != null && !name.trim().isEmpty())       property=name.trim();
      String desc=annotation.description();
      if (prefix != null && !prefix.isEmpty())       property=prefix + "." + property;
      if (print_class)       property=String.format("%s (%s)",property,clazz.getSimpleName());
      m.put(property,desc);
    }
    if (field.isAnnotationPresent(Component.class)) {
      Component ann=field.getAnnotation(Component.class);
      Class<?> type=field.getType();
      if (type.isInterface() || Modifier.isAbstract(type.getModifiers())) {
        Set<Class<?>> implementations=Util.findClassesAssignableFrom(ROOT_PACKAGE,type,Thread.currentThread().getContextClassLoader());
        for (        Class<?> impl : implementations)         getDescriptions(impl,m,ann.name(),true);
      }
 else       getDescriptions(type,m,ann.name(),false);
    }
  }
  Method[] methods=clazz.getDeclaredMethods();
  for (  Method method : methods) {
    if (method.isAnnotationPresent(Property.class)) {
      Property annotation=method.getAnnotation(Property.class);
      String desc=annotation.description();
      if (desc == null || desc.isEmpty())       desc="n/a";
      String name=annotation.name();
      if (name.length() < 1)       name=Util.methodNameToAttributeName(method.getName());
      if (prefix != null && !prefix.isEmpty())       name=prefix + "." + name;
      if (print_class)       name=String.format("%s (%s)",name,clazz.getSimpleName());
      m.put(name,desc);
    }
  }
}

